PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT(YEAR(?date) AS ?year) WHERE {
  ?tournament wdt:P3450 wd:Q996954 ; wdt:P585 ?date .
  FILTER(NOT EXISTS {
    wd:Q8027120 wdt:P397 ?season .
    ?season wdt:P1344 ?tournament
  })
  FILTER(?date <= NOW ())
}
ORDER BY DESC(?date)
LIMIT 1
